CREATE TABLE IF NOT EXISTS `zoneecologyloot` (
  `ZoneEcologyLoot_ID` varchar(255) NOT NULL,
  `RegionID` smallint(5) unsigned NOT NULL DEFAULT 0,
  `ZoneID` int(11) NOT NULL DEFAULT 0,
  `MobName` varchar(255) NOT NULL,
  `LootTemplateName` varchar(255) NOT NULL,
  `DropCount` int(11) NOT NULL DEFAULT 1,
  `DropsCoin` tinyint(1) NOT NULL DEFAULT 0,
  `Enabled` tinyint(1) NOT NULL DEFAULT 1,
  `LastTimeRowUpdated` datetime NOT NULL DEFAULT '2000-01-01 00:00:00',
  `Archetype` varchar(255) NOT NULL,
  `MaterialLootTemplateName` varchar(255) NOT NULL DEFAULT '',
  `MaterialDropChance` int(11) NOT NULL DEFAULT 0,
  `MaterialDropCount` int(11) NOT NULL DEFAULT 1,
  `IsNamed` tinyint(1) NOT NULL DEFAULT 0,
  `NamedXpMultiplier` double NOT NULL DEFAULT 1,
  `NamedXpCapMultiplier` double NOT NULL DEFAULT 1,
  `NamedRogChance` int(11) NOT NULL DEFAULT 0,
  `MinLevel` int(11) NOT NULL DEFAULT 0,
  `MaxLevel` int(11) NOT NULL DEFAULT 255,
  PRIMARY KEY (`ZoneEcologyLoot_ID`),
  KEY `I_ZoneEcologyLoot_RegionID` (`RegionID`),
  KEY `I_ZoneEcologyLoot_ZoneID` (`ZoneID`),
  KEY `I_ZoneEcologyLoot_MobName` (`MobName`),
  KEY `I_ZoneEcologyLoot_LootTemplateName` (`LootTemplateName`),
  KEY `I_ZoneEcologyLoot_Archetype` (`Archetype`),
  KEY `I_ZoneEcologyLoot_MaterialLootTemplateName` (`MaterialLootTemplateName`),
  KEY `I_ZoneEcologyLoot_MinLevel` (`MinLevel`),
  KEY `I_ZoneEcologyLoot_MaxLevel` (`MaxLevel`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

